"use strict";parserFactory.register("lightnovelstranslations.com",()=>new LightNovelsTranslationsParser);class LightNovelsTranslationsParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("li.chapter-item a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.text_story")}extractTitleImpl(e){return e.querySelector("div.novel_title h3")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.novel_info")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.novel_text")]}extractAuthor(e){const t=e.querySelector("div.novel_detail_info > ul > li:nth-child(1)");return t?t.textContent.replace("Author: ",""):"<unknown>"}}